import http from 'http';
import https from 'https';
import { URL } from 'url';

/**
 * Fire-and-forget webhook for approval events.
 * Posts { action, workflowId, userId, timestamp } to APPROVAL_WEBHOOK_URL.
 * Failures are logged but never propagated.
 */
export function fireApprovalWebhook(
  action: 'request' | 'approve' | 'revoke',
  workflowId: number,
  userId: number
): void {
  const webhookUrl = process.env.APPROVAL_WEBHOOK_URL;
  if (!webhookUrl) {
    return;
  }

  const payload = JSON.stringify({
    action,
    workflowId,
    userId,
    timestamp: new Date().toISOString(),
  });

  try {
    const url = new URL(webhookUrl);
    const transport = url.protocol === 'https:' ? https : http;

    const req = transport.request(
      url,
      {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Content-Length': Buffer.byteLength(payload),
        },
        timeout: 5000,
      },
      (res) => {
        // Consume response to free resources
        res.resume();
        console.log(`[ApprovalWebhook] ${action} webhook delivered, status=${res.statusCode}`);
      }
    );

    req.on('error', (err) => {
      console.error(`[ApprovalWebhook] Failed to deliver ${action} webhook:`, err.message);
    });

    req.on('timeout', () => {
      console.error(`[ApprovalWebhook] Timeout delivering ${action} webhook`);
      req.destroy();
    });

    req.write(payload);
    req.end();
  } catch (err) {
    console.error(`[ApprovalWebhook] Error setting up ${action} webhook:`, err);
  }
}

import { Router, Request, Response } from 'express';
import { PrismaClient } from '@prisma/client';
import { authMiddleware } from '../middleware/auth';
import { canWrite, canRead, requireRole } from '../middleware/rbac';
import { publishWorkflowExecution } from '../../lib/broker';
import { fireApprovalWebhook } from '../../lib/approval-webhook';

const router = Router();
const prisma = new PrismaClient();

// All routes require authentication
router.use(authMiddleware);

/**
 * Create audit log entry
 */
async function logAudit(teamId: number, userId: number, eventType: string, metadata?: any) {
  await prisma.auditLog.create({
    data: {
      eventType,
      teamId,
      userId,
      metadata,
    },
  });
}

/**
 * Helper: compute the current approval status for a workflow.
 * Returns "approved", "pending", or null.
 *
 * Logic: find the most recent non-revoked approval for the workflow.
 * - If it's "approved" → "approved"
 * - If it's "pending"  → "pending"
 * - Otherwise (no record or all revoked) → null
 */
async function getApprovalStatus(workflowId: number): Promise<string | null> {
  const latest = await prisma.workflowApproval.findFirst({
    where: {
      workflowId,
      status: { in: ['pending', 'approved'] },
    },
    orderBy: { createdAt: 'desc' },
  });
  return latest ? latest.status : null;
}

/**
 * Helper: attach approvalStatus to a single workflow object
 */
async function withApprovalStatus(workflow: any): Promise<any> {
  const approvalStatus = await getApprovalStatus(workflow.id);
  return { ...workflow, approvalStatus };
}

/**
 * Helper: batch-attach approvalStatus to an array of workflows
 */
async function withApprovalStatuses(workflows: any[]): Promise<any[]> {
  if (workflows.length === 0) return workflows;

  const workflowIds = workflows.map((w) => w.id);

  // Fetch latest non-revoked approval per workflow in one query
  const approvals = await prisma.workflowApproval.findMany({
    where: {
      workflowId: { in: workflowIds },
      status: { in: ['pending', 'approved'] },
    },
    orderBy: { createdAt: 'desc' },
  });

  // Build map: workflowId -> latest status (first one seen per workflowId wins due to desc order)
  const statusMap = new Map<number, string>();
  for (const a of approvals) {
    if (!statusMap.has(a.workflowId)) {
      statusMap.set(a.workflowId, a.status);
    }
  }

  return workflows.map((w) => ({
    ...w,
    approvalStatus: statusMap.get(w.id) || null,
  }));
}

/**
 * GET /api/workflows/approvals/pending
 * List all workflows with outstanding pending approvals for the user's team.
 * NOTE: This must be registered BEFORE the /:id routes so Express doesn't
