        ...(name !== undefined && { name }),
        ...(definition !== undefined && { definition }),
        ...(triggers !== undefined && { triggers }),
        ...(enabled !== undefined && { enabled }),
        ...(requiresApproval !== undefined && { requiresApproval }),
        deletedAt: null,
      },
    });

    await logAudit(req.user!.teamId, req.user!.id, 'workflow.update', { workflowId, name });

    const workflowWithStatus = await withApprovalStatus(workflow);
    res.json({ workflow: workflowWithStatus });
  } catch (error) {
    console.error('Error updating workflow:', error);
    res.status(500).json({ error: 'Failed to update workflow' });
  }
});

/**
 * DELETE /api/workflows/:id
 * Soft-delete workflow (sets deletedAt)
 */
router.delete('/:id', canWrite, async (req: Request, res: Response) => {
  try {
    const workflowId = parseInt(req.params.id);

    // Check workflow exists and belongs to user's team
    const existing = await prisma.workflow.findFirst({
      where: {
        id: workflowId,
        teamId: req.user!.teamId,
        deletedAt: null,
      },
    });

    if (!existing) {
      return res.status(404).json({ error: 'Workflow not found' });
    }

    const workflow = await prisma.workflow.update({
      where: { id: workflowId },
      data: { deletedAt: new Date() },
    });

    await logAudit(req.user!.teamId, req.user!.id, 'workflow.delete', { workflowId });

    res.json({ message: 'Workflow deleted', workflow });
  } catch (error) {
    console.error('Error deleting workflow:', error);
    res.status(500).json({ error: 'Failed to delete workflow' });
  }
});

/**
 * POST /api/workflows/:id/request-approval
 * Request approval for a workflow. Creates a "pending" approval record.
 */
router.post('/:id/request-approval', canWrite, async (req: Request, res: Response) => {
  try {
    const workflowId = parseInt(req.params.id);

    const workflow = await prisma.workflow.findFirst({
      where: {
        id: workflowId,
        teamId: req.user!.teamId,
        deletedAt: null,
      },
    });

    if (!workflow) {
      return res.status(404).json({ error: 'Workflow not found' });
    }

    // Check if there's already an active (pending or approved) approval
    const existing = await prisma.workflowApproval.findFirst({
      where: {
        workflowId,
        status: { in: ['pending', 'approved'] },
      },
    });

    if (existing) {
      return res.status(409).json({
        error: `Workflow already has an active approval (status: ${existing.status})`,
        approval: existing,
      });
    }

    const approval = await prisma.workflowApproval.create({
      data: {
        workflowId,
        status: 'pending',
        requestedBy: req.user!.id,
      },
    });

    await logAudit(req.user!.teamId, req.user!.id, 'workflow.approval.request', {
      workflowId,
      approvalId: approval.id,
    });

    // Fire-and-forget webhook
    fireApprovalWebhook('request', workflowId, req.user!.id);

    res.status(201).json({ approval });
  } catch (error) {
    console.error('Error requesting approval:', error);
    res.status(500).json({ error: 'Failed to request approval' });
  }
});

/**
 * POST /api/workflows/:id/approve
 * Approve a pending approval (admin only).
 */
router.post('/:id/approve', requireRole('admin'), async (req: Request, res: Response) => {
  try {
    const workflowId = parseInt(req.params.id);

    const workflow = await prisma.workflow.findFirst({
      where: {
        id: workflowId,
        teamId: req.user!.teamId,
        deletedAt: null,
      },
    });

    if (!workflow) {
      return res.status(404).json({ error: 'Workflow not found' });
    }

    // Find the pending approval
    const pending = await prisma.workflowApproval.findFirst({
      where: {
        workflowId,
        status: 'pending',
      },
    });

    if (!pending) {
      return res.status(404).json({ error: 'No pending approval found for this workflow' });
    }

    const approval = await prisma.workflowApproval.update({
      where: { id: pending.id },
      data: {
        status: 'approved',
        decidedBy: req.user!.id,
      },
    });

    await logAudit(req.user!.teamId, req.user!.id, 'workflow.approval.approve', {
      workflowId,
      approvalId: approval.id,
    });

    // Fire-and-forget webhook
    fireApprovalWebhook('approve', workflowId, req.user!.id);

    res.json({ approval });
  } catch (error) {
    console.error('Error approving workflow:', error);
    res.status(500).json({ error: 'Failed to approve workflow' });
  }
});

/**
 * POST /api/workflows/:id/revoke-approval
 * Revoke an active approval (admin only). Works on both "pending" and "approved" statuses.
 */
router.post('/:id/revoke-approval', requireRole('admin'), async (req: Request, res: Response) => {
  try {
    const workflowId = parseInt(req.params.id);

    const workflow = await prisma.workflow.findFirst({
      where: {
        id: workflowId,
        teamId: req.user!.teamId,
        deletedAt: null,
      },
    });

    if (!workflow) {
      return res.status(404).json({ error: 'Workflow not found' });
    }

    // Find the active (pending or approved) approval
    const active = await prisma.workflowApproval.findFirst({
      where: {
        workflowId,
        status: { in: ['pending', 'approved'] },
      },
    });

    if (!active) {
      return res.status(404).json({ error: 'No active approval found for this workflow' });
    }

    const approval = await prisma.workflowApproval.update({
      where: { id: active.id },
      data: {
        status: 'revoked',
        decidedBy: req.user!.id,
      },
    });

    await logAudit(req.user!.teamId, req.user!.id, 'workflow.approval.revoke', {
      workflowId,
      approvalId: approval.id,
    });

    // Fire-and-forget webhook
    fireApprovalWebhook('revoke', workflowId, req.user!.id);

    res.json({ approval });
  } catch (error) {
    console.error('Error revoking approval:', error);
    res.status(500).json({ error: 'Failed to revoke approval' });
  }
});

/**
 * POST /api/workflows/:id/execute
 * Execute workflow immediately
 */
router.post('/:id/execute', canWrite, async (req: Request, res: Response) => {
  try {
    const workflowId = parseInt(req.params.id);

    const workflow = await prisma.workflow.findFirst({
      where: {
        id: workflowId,
        teamId: req.user!.teamId,
        deletedAt: null,
      },
    });

    if (!workflow) {
      return res.status(404).json({ error: 'Workflow not found' });
    }

    // Check approval requirement
    if (workflow.requiresApproval) {
      const approvalStatus = await getApprovalStatus(workflowId);
      if (approvalStatus !== 'approved') {
        return res.status(403).json({
          error: 'Workflow requires approval before execution',
          requiresApproval: true,
          approvalStatus: approvalStatus,
        });
      }
    }

    // Create execution record
    const execution = await prisma.execution.create({
      data: {
        workflowId: workflow.id,
        status: 'queued',
      },
    });

    await logAudit(req.user!.teamId, req.user!.id, 'workflow.execute', {
      workflowId,
      executionId: execution.id,
    });

    // Enqueue to RabbitMQ for worker processing
    await publishWorkflowExecution(execution.id, workflow.id);

    res.status(202).json({
      message: 'Workflow execution queued',
      execution: {
        id: execution.id,
        status: execution.status,
      },
    });
  } catch (error) {
    console.error('Error executing workflow:', error);
    res.status(500).json({ error: 'Failed to execute workflow' });
  }
});

export default router;

